import { MakeLogicType, actions, kea, key, listeners, path, props, reducers, selectors } from 'kea'

import posthog from 'lib/posthog-typed'

export type ExceptionCardLogicProps = {
    issueId: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface exceptionCardLogicValues {
    currentSessionTab: string
    currentTab: string
    expandedFrameRawIds: Set<string>
    issueId: string
    loading: boolean
    showAdditionalProperties: boolean
    showJSONProperties: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface exceptionCardLogicActions {
    setCurrentSessionTab: (tab: string) => {
        tab: string
    }
    setCurrentTab: (tab: string) => {
        tab: string
    }
    setFrameExpanded: (
        rawId: string,
        expanded: boolean
    ) => {
        expanded: boolean
        rawId: string
    }
    setLoading: (loading: boolean) => {
        loading: boolean
    }
    setShowAdditionalProperties: (showProperties: boolean) => {
        showProperties: boolean
    }
    setShowJSONProperties: (showJSON: boolean) => {
        showJSON: boolean
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface exceptionCardLogicMeta {
    key: string
    __keaTypeGenInternalSelectorTypes: {
        issueId: (issueId: string) => string
    }
}

export type exceptionCardLogicType = MakeLogicType<
    exceptionCardLogicValues,
    exceptionCardLogicActions,
    ExceptionCardLogicProps,
    exceptionCardLogicMeta
>

export const exceptionCardLogic = kea<exceptionCardLogicType>([
    path((key) => ['products', 'error_tracking', 'ExceptionCard', key]),
    key((props) => props.issueId),
    props({} as ExceptionCardLogicProps),

    actions({
        setShowJSONProperties: (showJSON: boolean) => ({ showJSON }),
        setShowAdditionalProperties: (showProperties: boolean) => ({ showProperties }),
        setLoading: (loading: boolean) => ({ loading }),
        setCurrentSessionTab: (tab: string) => ({ tab }),
        setCurrentTab: (tab: string) => ({ tab }),
        setFrameExpanded: (rawId: string, expanded: boolean) => ({ rawId, expanded }),
    }),

    reducers({
        expandedFrameRawIds: [
            new Set<string>(),
            {
                setFrameExpanded: (state, { rawId, expanded }) => {
                    const has = state.has(rawId)
                    if (expanded === has) {
                        return state
                    }
                    const next = new Set(state)
                    if (expanded) {
                        next.add(rawId)
                    } else {
                        next.delete(rawId)
                    }
                    return next
                },
            },
        ],
        showJSONProperties: [
            false,
            {
                setShowJSONProperties: (_, { showJSON }) => showJSON,
            },
        ],
        showAdditionalProperties: [
            true,
            {
                setShowAdditionalProperties: (_, { showProperties }) => showProperties,
            },
        ],
        loading: [
            true,
            {
                setLoading: (_, { loading }: { loading: boolean }) => loading,
            },
        ],
        currentSessionTab: [
            'timeline',
            {
                setCurrentSessionTab: (_, { tab }: { tab: string }) => tab,
            },
        ],
        currentTab: [
            'stack_trace',
            {
                setCurrentTab: (_, { tab }: { tab: string }) => tab,
            },
        ],
    }),

    selectors({
        issueId: [(_, p) => [p.issueId], (issueId: string) => issueId],
    }),

    listeners(({ props }) => ({
        setFrameExpanded: ({ expanded }) => {
            if (expanded) {
                posthog.capture('error_tracking_stacktrace_explored', { issue_id: props.issueId })
            }
        },
    })),
])
